 41→export type EventEntry = { text: string | undefined; json: string };
 42→
 43→export type IpcSocket = {
 44→  write(data: string | Uint8Array): number;
 45→  end(): void;
 46→};
 47→
 48→export type IpcCommand =
 49→  | { type: "chat"; message: string }
 50→  | { type: "say"; message: string }
 51→  | { type: "yell"; message: string }
 52→  | { type: "guild"; message: string }
 53→  | { type: "party"; message: string }
 54→  | { type: "emote"; message: string }
 55→  | { type: "dnd"; message: string }
 56→  | { type: "afk"; message: string }
 57→  | { type: "whisper"; target: string; message: string }
 58→  | { type: "read" }
 59→  | { type: "read_json" }
 60→  | { type: "read_wait"; ms: number }
 61→  | { type: "read_wait_json"; ms: number }
 62→  | { type: "stop" }
 63→  | { type: "status" }
 64→  | { type: "who"; filter?: string }
 65→  | { type: "who_json"; filter?: string }
 66→  | { type: "invite"; target: string }
 67→  | { type: "kick"; target: string }
 68→  | { type: "leave" }
 69→  | { type: "join_channel"; channel: string; password?: string }
 70→  | { type: "leave_channel"; channel: string }
 71→  | { type: "leader"; target: string }
 72→  | { type: "accept" }
 73→  | { type: "decline" }
 74→  | { type: "nearby" }
 75→  | { type: "nearby_json" }
 76→  | { type: "friends" }
 77→  | { type: "friends_json" }
 78→  | { type: "add_friend"; target: string }
 79→  | { type: "del_friend"; target: string }
 80→  | { type: "ignored" }
 81→  | { type: "ignored_json" }
 82→  | { type: "add_ignore"; target: string }
 83→  | { type: "del_ignore"; target: string }
 84→  | { type: "roll"; min: number; max: number }
 85→  | { type: "guild_roster" }
 86→  | { type: "guild_roster_json" }
 87→  | { type: "guild_invite"; target: string }
 88→  | { type: "guild_kick"; target: string }
 89→  | { type: "guild_leave" }
 90→  | { type: "guild_promote"; target: string }
 91→  | { type: "guild_demote"; target: string }
 92→  | { type: "guild_leader"; target: string }
 93→  | { type: "guild_motd"; message: string }
 94→  | { type: "guild_accept" }
 95→  | { type: "guild_decline" }
 96→  | { type: "unimplemented"; feature: string };
 97→
 98→export function parseIpcCommand(line: string): IpcCommand | undefined {
 99→  if (line.startsWith("/")) {
100→    const parsed = parseCommand(line);
101→    switch (parsed.type) {
102→      case "say":
103→      case "yell":
104→      case "guild":
105→      case "party":
106→      case "emote":
107→      case "dnd":
108→      case "afk":
109→        return parsed;
110→      case "whisper":
111→        return parsed;
112→      case "who":
113→        return parsed.target
114→          ? { type: "who", filter: parsed.target }
115→          : { type: "who" };
116→      case "invite":
117→      case "kick":
118→      case "leave":
119→      case "leader":
120→      case "accept":
121→      case "decline":
122→        return parsed;
123→      case "join-channel":
124→        return {
125→          type: "join_channel",
126→          channel: parsed.channel,
127→          password: parsed.password,
128→        };
129→      case "leave-channel":
130→        return { type: "leave_channel", channel: parsed.channel };
131→      case "friends":
132→        return { type: "friends" };
133→      case "add-friend":
134→        return { type: "add_friend", target: parsed.target };
135→      case "remove-friend":
136→        return { type: "del_friend", target: parsed.target };
137→      case "ignored":
138→        return { type: "ignored" };
139→      case "add-ignore":
140→        return { type: "add_ignore", target: parsed.target };
141→      case "remove-ignore":
142→        return { type: "del_ignore", target: parsed.target };
143→      case "roll":
144→        return parsed;
145→      case "guild-roster":
146→        return { type: "guild_roster" };
147→      case "guild-invite":
148→        return { type: "guild_invite", target: parsed.target };
149→      case "guild-kick":
150→        return { type: "guild_kick", target: parsed.target };
151→      case "guild-leave":
152→        return { type: "guild_leave" };
153→      case "guild-promote":
154→        return { type: "guild_promote", target: parsed.target };
155→      case "guild-demote":
156→        return { type: "guild_demote", target: parsed.target };
157→      case "guild-leader":
158→        return { type: "guild_leader", target: parsed.target };
159→      case "guild-motd":
160→        return { type: "guild_motd", message: parsed.message };
161→      case "guild-accept":
162→        return { type: "guild_accept" };
163→      case "guild-decline":
164→        return { type: "guild_decline" };
165→      case "unimplemented":
166→        return parsed;
167→      default:
168→        return { type: "say", message: line };
169→    }
170→  }
171→
172→  const spaceIdx = line.indexOf(" ");
173→  const verb = spaceIdx === -1 ? line : line.slice(0, spaceIdx);
174→  const rest = spaceIdx === -1 ? "" : line.slice(spaceIdx + 1);
175→
176→  switch (verb) {
177→    case "SAY":
178→    case "YELL":
179→    case "GUILD":
180→    case "PARTY":
181→    case "EMOTE":
182→    case "DND":
183→    case "AFK":
184→      return {
185→        type: verb.toLowerCase() as
186→          | "say"
187→          | "yell"
188→          | "guild"
189→          | "party"
190→          | "emote"
191→          | "dnd"
192→          | "afk",
193→        message: rest,
194→      };
195→    case "WHISPER": {
196→      const targetEnd = rest.indexOf(" ");
197→      if (targetEnd === -1)
198→        return { type: "whisper", target: rest, message: "" };
199→      return {
200→        type: "whisper",
201→        target: rest.slice(0, targetEnd),
202→        message: rest.slice(targetEnd + 1),
203→      };
204→    }
205→    case "READ":
206→      return { type: "read" };
207→    case "READ_JSON":
208→      return { type: "read_json" };
209→    case "READ_WAIT": {
210→      const ms = parseInt(rest, 10);
211→      if (!Number.isFinite(ms) || ms < 0) return undefined;
212→      return { type: "read_wait", ms: Math.min(ms, 60_000) };
213→    }
214→    case "READ_WAIT_JSON": {
215→      const ms = parseInt(rest, 10);
216→      if (!Number.isFinite(ms) || ms < 0) return undefined;
217→      return { type: "read_wait_json", ms: Math.min(ms, 60_000) };
218→    }
219→    case "STOP":
220→      return { type: "stop" };
221→    case "STATUS":
222→      return { type: "status" };
223→    case "WHO":
224→      return rest ? { type: "who", filter: rest } : { type: "who" };
225→    case "WHO_JSON":
226→      return rest ? { type: "who_json", filter: rest } : { type: "who_json" };
227→    case "INVITE":
228→      return rest ? { type: "invite", target: rest } : undefined;
229→    case "KICK":
230→      return rest ? { type: "kick", target: rest } : undefined;
231→    case "LEAVE":
232→      if (rest) {
233→        const channel = rest.split(" ")[0]!;
234→        return { type: "leave_channel", channel };
235→      }
236→      return { type: "leave" };
237→    case "LEADER":
238→      return rest ? { type: "leader", target: rest } : undefined;
239→    case "ACCEPT":
240→      return { type: "accept" };
241→    case "DECLINE":
242→      return { type: "decline" };
243→    case "NEARBY":
244→      return { type: "nearby" };
245→    case "NEARBY_JSON":
246→      return { type: "nearby_json" };
247→    case "FRIENDS":
248→      return { type: "friends" };
249→    case "FRIENDS_JSON":
250→      return { type: "friends_json" };
251→    case "ADD_FRIEND":
252→      return rest ? { type: "add_friend", target: rest } : undefined;
253→    case "DEL_FRIEND":
254→      return rest ? { type: "del_friend", target: rest } : undefined;
255→    case "IGNORED":
256→      return { type: "ignored" };
257→    case "IGNORED_JSON":
258→      return { type: "ignored_json" };
259→    case "ADD_IGNORE":
260→      return rest ? { type: "add_ignore", target: rest } : undefined;
261→    case "DEL_IGNORE":
262→      return rest ? { type: "del_ignore", target: rest } : undefined;
263→    case "JOIN": {
264→      if (!rest) return undefined;
265→      const [channel, password] = rest.split(" ") as [string, string?];
266→      return { type: "join_channel", channel, password };
267→    }
268→    case "GUILD_ROSTER":
269→      return { type: "guild_roster" };
270→    case "GUILD_ROSTER_JSON":
271→      return { type: "guild_roster_json" };
272→    case "GINVITE":
273→      return rest ? { type: "guild_invite", target: rest } : undefined;
274→    case "GKICK":
275→      return rest ? { type: "guild_kick", target: rest } : undefined;
276→    case "GLEAVE":
277→      return { type: "guild_leave" };
278→    case "GPROMOTE":
279→      return rest ? { type: "guild_promote", target: rest } : undefined;
280→    case "GDEMOTE":
281→      return rest ? { type: "guild_demote", target: rest } : undefined;
282→    case "GLEADER":
283→      return rest ? { type: "guild_leader", target: rest } : undefined;
284→    case "GMOTD":
285→      return { type: "guild_motd", message: rest };
286→    case "GACCEPT":
287→      return { type: "guild_accept" };
288→    case "GDECLINE":
289→      return { type: "guild_decline" };
290→    case "MAIL":
291→      return { type: "unimplemented", feature: "Mail reading" };
292→    case "ROLL": {
293→      const parts = rest.split(" ").filter(Boolean);
294→      if (parts.length >= 2)
295→        return {
296→          type: "roll",
297→          min: parseInt(parts[0]!, 10),
298→          max: parseInt(parts[1]!, 10),
299→        };
300→      if (parts.length === 1)
301→        return { type: "roll", min: 1, max: parseInt(parts[0]!, 10) };
302→      return { type: "roll", min: 1, max: 100 };
303→    }
304→    default:
305→      return line ? { type: "chat", message: line } : undefined;
306→  }
307→}
308→
309→export function writeLines(socket: IpcSocket, lines: string[]): void {
310→  for (const line of lines) socket.write(line + "\n");
311→  socket.write("\n");
312→}
313→
314→function drainText(events: RingBuffer<EventEntry>): string[] {
315→  return events.drain().flatMap((e) => (e.text !== undefined ? [e.text] : []));
316→}
317→
318→function drainJson(events: RingBuffer<EventEntry>): string[] {
319→  return events.drain().map((e) => e.json);
320→}
321→
322→function sliceText(events: RingBuffer<EventEntry>, from: number): string[] {
323→  return events
324→    .slice(from)
325→    .flatMap((e) => (e.text !== undefined ? [e.text] : []));
326→}
327→
328→function sliceJson(events: RingBuffer<EventEntry>, from: number): string[] {
329→  return events.slice(from).map((e) => e.json);
330→}
331→
332→export async function dispatchCommand(
333→  cmd: IpcCommand,
334→  handle: WorldHandle,
335→  events: RingBuffer<EventEntry>,
336→  socket: IpcSocket,
337→  cleanup: () => void,
338→): Promise<boolean> {
339→  switch (cmd.type) {
340→    case "chat": {
341→      handle.sendInCurrentMode(cmd.message);
342→      const mode = handle.getLastChatMode();
343→      const label =
344→        mode.type === "whisper"
345→          ? `WHISPER ${mode.target}`
346→          : mode.type === "channel"
347→            ? `CHANNEL ${mode.channel}`
348→            : mode.type.toUpperCase();
349→      writeLines(socket, [`OK ${label}`]);
350→      return false;
351→    }
352→    case "say":
353→      handle.sendSay(cmd.message);
354→      writeLines(socket, ["OK"]);
355→      return false;
356→    case "yell":
357→      handle.sendYell(cmd.message);
358→      writeLines(socket, ["OK"]);
359→      return false;
360→    case "guild":
361→      handle.sendGuild(cmd.message);
362→      writeLines(socket, ["OK"]);
363→      return false;
364→    case "party":
365→      handle.sendParty(cmd.message);
366→      writeLines(socket, ["OK"]);
367→      return false;
368→    case "emote":
369→      handle.sendEmote(cmd.message);
370→      writeLines(socket, ["OK"]);
371→      return false;
372→    case "dnd":
373→      handle.sendDnd(cmd.message);
374→      writeLines(socket, ["OK"]);
375→      return false;
376→    case "afk":
377→      handle.sendAfk(cmd.message);
378→      writeLines(socket, ["OK"]);
379→      return false;
380→    case "whisper":
381→      handle.sendWhisper(cmd.target, cmd.message);
382→      writeLines(socket, ["OK"]);
383→      return false;
384→    case "roll":
385→      handle.sendRoll(cmd.min, cmd.max);
386→      writeLines(socket, ["OK"]);
387→      return false;
388→    case "read":
389→      writeLines(socket, drainText(events));
390→      return false;
391→    case "read_json":
392→      writeLines(socket, drainJson(events));
393→      return false;
394→    case "read_wait": {
395→      const start = events.writePos;
396→      await new Promise<void>((resolve) => {
397→        setTimeout(() => {
398→          writeLines(socket, sliceText(events, start));
399→          resolve();
400→        }, cmd.ms);
401→      });
402→      return false;
403→    }
404→    case "read_wait_json": {
405→      const start = events.writePos;
406→      await new Promise<void>((resolve) => {
407→        setTimeout(() => {
408→          writeLines(socket, sliceJson(events, start));
409→          resolve();
410→        }, cmd.ms);
411→      });
412→      return false;
413→    }
414→    case "stop":
415→      writeLines(socket, ["OK"]);
416→      cleanup();
417→      return true;
418→    case "status":
419→      writeLines(socket, ["CONNECTED"]);
420→      return false;
421→    case "who": {
422→      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
423→      writeLines(socket, formatWhoResults(results).split("\n"));
424→      return false;
425→    }
426→    case "who_json": {
427→      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
428→      writeLines(socket, [formatWhoResultsJson(results)]);
429→      return false;
430→    }
431→    case "invite":
432→      handle.invite(cmd.target);
433→      writeLines(socket, ["OK"]);
434→      return false;
435→    case "kick":
436→      handle.uninvite(cmd.target);
437→      writeLines(socket, ["OK"]);
438→      return false;
439→    case "leave":
440→      handle.leaveGroup();
441→      writeLines(socket, ["OK"]);
442→      return false;
443→    case "leader":
444→      handle.setLeader(cmd.target);
445→      writeLines(socket, ["OK"]);
446→      return false;
447→    case "accept":
448→      handle.acceptInvite();
449→      writeLines(socket, ["OK"]);
450→      return false;
451→    case "decline":
452→      handle.declineInvite();
453→      writeLines(socket, ["OK"]);
454→      return false;
455→    case "nearby": {
456→      const entities = handle.getNearbyEntities();
457→      writeLines(socket, entities.map(formatNearbyLine));
458→      return false;
459→    }
460→    case "nearby_json": {
461→      const entities = handle.getNearbyEntities();
462→      writeLines(
463→        socket,
464→        entities.map((e) => JSON.stringify(formatNearbyObj(e))),
465→      );
466→      return false;
467→    }
468→    case "friends": {
469→      const friends = handle.getFriends();
470→      writeLines(socket, formatFriendList(friends).split("\n"));
471→      return false;
472→    }
473→    case "friends_json": {
474→      const friends = handle.getFriends();
475→      writeLines(socket, [formatFriendListJson(friends)]);
476→      return false;
477→    }
478→    case "add_friend":
479→      handle.addFriend(cmd.target);
480→      writeLines(socket, ["OK"]);
481→      return false;
482→    case "del_friend":
483→      handle.removeFriend(cmd.target);
484→      writeLines(socket, ["OK"]);
485→      return false;
486→    case "ignored": {
487→      const ignored = handle.getIgnored();
488→      writeLines(socket, formatIgnoreList(ignored).split("\n"));
489→      return false;
490→    }
491→    case "ignored_json": {
492→      const ignored = handle.getIgnored();
493→      writeLines(socket, [formatIgnoreListJson(ignored)]);
494→      return false;
495→    }
496→    case "add_ignore":
497→      handle.addIgnore(cmd.target);
498→      writeLines(socket, ["OK"]);
499→      return false;
500→    case "del_ignore":
501→      handle.removeIgnore(cmd.target);
502→      writeLines(socket, ["OK"]);
503→      return false;
504→    case "join_channel":
505→      handle.joinChannel(cmd.channel, cmd.password);
506→      writeLines(socket, ["OK"]);
507→      return false;
508→    case "leave_channel":
509→      handle.leaveChannel(cmd.channel);
510→      writeLines(socket, ["OK"]);
511→      return false;
512→    case "guild_roster": {
513→      const roster = await handle.requestGuildRoster();
514→      if (roster) {
515→        writeLines(socket, formatGuildRoster(roster).split("\n"));
516→      } else {
517→        writeLines(socket, ["[guild] No guild roster available"]);
518→      }
519→      return false;
520→    }
521→    case "guild_roster_json": {
522→      const roster = await handle.requestGuildRoster();
523→      if (roster) {
524→        writeLines(socket, [formatGuildRosterJson(roster)]);
525→      } else {
526→        writeLines(socket, [
527→          JSON.stringify({ type: "GUILD_ROSTER", members: [] }),
528→        ]);
529→      }
530→      return false;
531→    }
532→    case "guild_invite":
533→      handle.guildInvite(cmd.target);
534→      writeLines(socket, ["OK"]);
535→      return false;
536→    case "guild_kick":
537→      handle.guildRemove(cmd.target);
538→      writeLines(socket, ["OK"]);
539→      return false;
540→    case "guild_leave":
541→      handle.guildLeave();
542→      writeLines(socket, ["OK"]);
543→      return false;
544→    case "guild_promote":
545→      handle.guildPromote(cmd.target);
546→      writeLines(socket, ["OK"]);
547→      return false;
548→    case "guild_demote":
549→      handle.guildDemote(cmd.target);
550→      writeLines(socket, ["OK"]);
551→      return false;
552→    case "guild_leader":
553→      handle.guildLeader(cmd.target);
554→      writeLines(socket, ["OK"]);
555→      return false;
556→    case "guild_motd":
557→      handle.guildMotd(cmd.message);
558→      writeLines(socket, ["OK"]);
559→      return false;
560→    case "guild_accept":
561→      handle.acceptGuildInvite();
562→      writeLines(socket, ["OK"]);
563→      return false;
564→    case "guild_decline":
565→      handle.declineGuildInvite();
566→      writeLines(socket, ["OK"]);
567→      return false;
568→    case "unimplemented":
569→      writeLines(socket, [`UNIMPLEMENTED ${cmd.feature}`]);
570→      return false;
571→  }
572→}
